import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { useGame } from '../hooks/useGameState';
import { NBA_TEAMS } from '../data/nbaData';

export default function StartGame() {
  const { startGame, gameState } = useGame();
  const navigate = useNavigate();
  const [screen, setScreen] = useState('main'); // 'main', 'new-game', 'team-select'
  const [gmName, setGmName] = useState('');
  const [selectedTeam, setSelectedTeam] = useState(null);
  const [loading, setLoading] = useState(false);
  const [conferenceFilter, setConferenceFilter] = useState('All');

  const styles = {
    startScreen: {
      minHeight: '100vh',
      background: 'linear-gradient(135deg, #0a0a0f 0%, #16161f 100%)',
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'center',
      position: 'relative',
      overflow: 'hidden',
      padding: '40px'
    },
    container: {
      position: 'relative',
      zIndex: 2,
      width: '100%',
      maxWidth: '1400px'
    },
    mainMenu: {
      textAlign: 'center'
    },
    title: {
      fontSize: '72px',
      fontWeight: '900',
      fontFamily: "'Bebas Neue', sans-serif",
      letterSpacing: '4px',
      margin: '0 0 20px 0',
      color: 'var(--text-primary)'
    },
    subtitle: {
      fontSize: '18px',
      color: 'var(--text-secondary)',
      marginBottom: '60px',
      letterSpacing: '2px',
      textTransform: 'uppercase'
    },
    menuBtn: {
      display: 'flex',
      alignItems: 'center',
      gap: '20px',
      padding: '24px',
      background: 'var(--bg-card)',
      border: '2px solid var(--border)',
      borderRadius: '12px',
      cursor: 'pointer',
      transition: 'all 0.3s',
      marginBottom: '16px',
      maxWidth: '600px',
      marginLeft: 'auto',
      marginRight: 'auto'
    },
    teamGrid: {
      display: 'grid',
      gridTemplateColumns: 'repeat(auto-fill, minmax(280px, 1fr))',
      gap: '16px',
      marginBottom: '100px',
      maxHeight: '60vh',
      overflowY: 'auto',
      padding: '4px'
    },
    teamCard: {
      position: 'relative',
      padding: '24px',
      background: 'var(--bg-card)',
      border: '2px solid var(--border)',
      borderRadius: '12px',
      cursor: 'pointer',
      transition: 'all 0.3s'
    },
    teamCardSelected: {
      borderColor: 'var(--accent)',
      boxShadow: '0 0 0 4px rgba(232, 255, 71, 0.2)'
    },
    footer: {
      position: 'fixed',
      bottom: 0,
      left: 0,
      right: 0,
      padding: '24px 40px',
      background: 'linear-gradient(to top, #0a0a0f 80%, transparent)',
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'space-between',
      zIndex: 10
    },
    startBtn: {
      padding: '20px 32px',
      background: 'var(--accent)',
      border: 'none',
      borderRadius: '12px',
      fontSize: '18px',
      fontWeight: '700',
      color: '#0a0a0f',
      cursor: 'pointer',
      minWidth: '300px'
    }
  };

  // Check if there's an active game and redirect
  useEffect(() => {
    if (gameState && screen === 'main') {
      // Auto-redirect to dashboard if game is already loaded
      navigate('/dashboard');
    }
  }, [gameState, navigate, screen]);

  const handleStart = () => {
    if (gmName.trim() && selectedTeam) {
      setLoading(true);
      try {
        startGame(selectedTeam.id, gmName);
        setTimeout(() => {
          navigate('/dashboard');
        }, 100);
      } catch (error) {
        console.error('Failed to start game:', error);
        setLoading(false);
      }
    }
  };

  const filteredTeams = NBA_TEAMS.filter(t => 
    conferenceFilter === 'All' || t.conf === conferenceFilter
  );

  return (
    <div style={styles.startScreen}>
      <div style={styles.container}>
        {/* MAIN MENU */}
        {screen === 'main' && (
          <div style={styles.mainMenu}>
            <div style={{fontSize: '80px', marginBottom: '20px'}}>🏀</div>
            <h1 style={styles.title}>FRONT<span style={{color: 'var(--accent)'}}>OFFICE</span></h1>
            <p style={styles.subtitle}>Build Your Dynasty</p>

            <button
              style={{...styles.menuBtn, borderColor: 'var(--accent)', background: 'var(--accent-dim)'}}
              onClick={() => setScreen('new-game')}
            >
              <div style={{fontSize: '40px'}}>🆕</div>
              <div style={{flex: 1, textAlign: 'left'}}>
                <div style={{fontSize: '24px', fontWeight: 700, color: 'var(--text-primary)'}}>New Game</div>
                <div style={{fontSize: '14px', color: 'var(--text-secondary)'}}>Start a fresh season</div>
              </div>
            </button>
          </div>
        )}

        {/* NEW GAME - GM NAME */}
        {screen === 'new-game' && (
          <div>
            <button
              style={{padding: '12px 20px', background: 'var(--bg-card)', border: '1px solid var(--border)', borderRadius: '8px', color: 'var(--text-secondary)', cursor: 'pointer', marginBottom: '32px'}}
              onClick={() => setScreen('main')}
            >
              ← Back
            </button>

            <div style={{maxWidth: '600px', margin: '0 auto', textAlign: 'center'}}>
              <h2 style={{fontSize: '42px', fontWeight: 800, marginBottom: '12px'}}>Create Your Identity</h2>
              <p style={{fontSize: '16px', color: 'var(--text-secondary)', marginBottom: '48px'}}>Enter your name to begin your journey</p>

              <input
                type="text"
                value={gmName}
                onChange={(e) => setGmName(e.target.value)}
                placeholder="Enter your name..."
                style={{
                  width: '100%',
                  padding: '20px 24px',
                  background: 'var(--bg-card)',
                  border: '2px solid var(--border)',
                  borderRadius: '12px',
                  fontSize: '24px',
                  fontWeight: 600,
                  color: 'var(--text-primary)',
                  textAlign: 'center',
                  fontFamily: "'Bebas Neue', sans-serif",
                  letterSpacing: '2px',
                  marginBottom: '32px'
                }}
                onKeyDown={(e) => e.key === 'Enter' && gmName.trim() && setScreen('team-select')}
                autoFocus
              />

              <button
                onClick={() => gmName.trim() && setScreen('team-select')}
                disabled={!gmName.trim()}
                style={{
                  ...styles.startBtn,
                  width: '100%',
                  opacity: gmName.trim() ? 1 : 0.4
                }}
              >
                Continue to Team Selection →
              </button>
            </div>
          </div>
        )}

        {/* TEAM SELECTION */}
        {screen === 'team-select' && (
          <div>
            <div style={{display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: '32px'}}>
              <button
                style={{padding: '12px 20px', background: 'var(--bg-card)', border: '1px solid var(--border)', borderRadius: '8px', color: 'var(--text-secondary)', cursor: 'pointer'}}
                onClick={() => {
                  setScreen('new-game');
                  setSelectedTeam(null);
                }}
              >
                ← Back
              </button>
              <h2 style={{fontSize: '32px', fontWeight: 800}}>Choose Your Franchise</h2>
              <div style={{width: '80px'}}></div>
            </div>

            <div style={{display: 'flex', gap: '8px', justifyContent: 'center', marginBottom: '32px'}}>
              {['All', 'East', 'West'].map(conf => (
                <button
                  key={conf}
                  style={{
                    padding: '10px 24px',
                    background: conferenceFilter === conf ? 'var(--accent-dim)' : 'var(--bg-card)',
                    border: `2px solid ${conferenceFilter === conf ? 'var(--accent)' : 'var(--border)'}`,
                    borderRadius: '8px',
                    color: conferenceFilter === conf ? 'var(--accent)' : 'var(--text-secondary)',
                    fontSize: '14px',
                    fontWeight: 700,
                    cursor: 'pointer'
                  }}
                  onClick={() => setConferenceFilter(conf)}
                >
                  {conf === 'All' ? 'All Teams' : `${conf}ern`}
                </button>
              ))}
            </div>

            <div style={styles.teamGrid}>
              {filteredTeams.map((team) => (
                <div
                  key={team.id}
                  style={{
                    ...styles.teamCard,
                    ...(selectedTeam?.id === team.id ? styles.teamCardSelected : {})
                  }}
                  onClick={() => setSelectedTeam(team)}
                >
                  <div style={{fontSize: '48px', marginBottom: '16px'}}>{team.emoji}</div>
                  <div style={{fontSize: '28px', fontWeight: 900, fontFamily: "'Bebas Neue', sans-serif", letterSpacing: '2px', marginBottom: '4px'}}>{team.abbr}</div>
                  <div style={{fontSize: '14px', fontWeight: 600, marginBottom: '2px'}}>{team.name}</div>
                  <div style={{fontSize: '12px', color: 'var(--text-secondary)', marginBottom: '12px'}}>{team.city}</div>
                  <div style={{display: 'flex', alignItems: 'baseline', gap: '8px'}}>
                    <span style={{fontSize: '11px', fontWeight: 700, textTransform: 'uppercase', color: 'var(--text-secondary)'}}>OVR</span>
                    <span style={{fontSize: '32px', fontWeight: 900, fontFamily: "'Bebas Neue', sans-serif", color: 'var(--accent)'}}>{team.rating}</span>
                  </div>
                  {selectedTeam?.id === team.id && (
                    <div style={{
                      position: 'absolute',
                      top: '12px',
                      right: '12px',
                      width: '32px',
                      height: '32px',
                      background: 'var(--accent)',
                      borderRadius: '50%',
                      display: 'flex',
                      alignItems: 'center',
                      justifyContent: 'center',
                      color: '#0a0a0f',
                      fontSize: '18px',
                      fontWeight: 900
                    }}>✓</div>
                  )}
                </div>
              ))}
            </div>

            {selectedTeam && (
              <div style={styles.footer}>
                <div style={{display: 'flex', alignItems: 'center', gap: '12px'}}>
                  <span style={{color: 'var(--text-secondary)'}}>Selected:</span>
                  <span style={{fontSize: '32px'}}>{selectedTeam.emoji}</span>
                  <span style={{color: 'var(--accent)', fontSize: '20px', fontWeight: 600}}>{selectedTeam.name}</span>
                </div>
                <button
                  onClick={handleStart}
                  disabled={loading}
                  style={styles.startBtn}
                >
                  {loading ? 'Loading...' : `Start Season 🚀`}
                </button>
              </div>
            )}
          </div>
        )}
      </div>
    </div>
  );
}
